import React, { createContext, useState, useContext, ReactNode } from 'react';

// Define the shape of our user data
interface UserProfile {
  name: string;
  role: string;
  currentSkills: string[];
  learningGoals: string[];
  learningPath: string[];
  experienceYears?: number;
  fieldOfExperience?: string;
}

interface UserContextType {
  userProfile: UserProfile;
  updateUserProfile: (updates: Partial<UserProfile>) => void;
  addToLearningPath: (item: string) => void;
  // We can add more state here later (e.g., saved courses, quiz scores)
}

const defaultProfile: UserProfile = {
  name: "Guest User",
  role: "Aspiring AI Engineer",
  currentSkills: ["Python", "JavaScript"],
  learningGoals: ["Machine Learning", "Cloud Architecture"],
  learningPath: [],
  experienceYears: 0,
  fieldOfExperience: "General Tech",
};

const UserContext = createContext<UserContextType | undefined>(undefined);

export const UserProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [userProfile, setUserProfile] = useState<UserProfile>(() => {
    if (typeof window === 'undefined') return defaultProfile;
    try {
      const storedProfile = window.localStorage.getItem('userProfile');
      return storedProfile ? JSON.parse(storedProfile) : defaultProfile;
    } catch {
      return defaultProfile;
    }
  });

  const updateUserProfile = (updates: Partial<UserProfile>) => {
    setUserProfile((prev) => ({ ...prev, ...updates }));
  };

  const addToLearningPath = (item: string) => {
    setUserProfile((prev) => {
      if (prev.learningPath.includes(item)) return prev;
      return { ...prev, learningPath: [...prev.learningPath, item] };
    });
  };

  React.useEffect(() => {
    try {
      window.localStorage.setItem('userProfile', JSON.stringify(userProfile));
    } catch {
      // Ignore persistence failures in unsupported browsers.
    }
  }, [userProfile]);

  return (
    <UserContext.Provider value={{ userProfile, updateUserProfile, addToLearningPath }}>
      {children}
    </UserContext.Provider>
  );
};

export const useUser = (): UserContextType => {
  const context = useContext(UserContext);
  if (context === undefined) {
    throw new Error('useUser must be used within a UserProvider');
  }
  return context;
};
